"""Embedded XSD schema data.

XSD content is compressed and decompressed at runtime.
"""

import zlib as _z, base64 as _b

_TRANSFORMGRAPH_XSD_COMPRESSED = _b.b64decode(
    ""
)

_transformgraph_xsd_cache = None


def get_transformgraph_xsd() -> str:
    """Return the TransformGraph XSD content (decompressed on first call)."""
    global _transformgraph_xsd_cache
    if _transformgraph_xsd_cache is None:
        _transformgraph_xsd_cache = _z.decompress(_TRANSFORMGRAPH_XSD_COMPRESSED).decode("utf-8")
    return _transformgraph_xsd_cache
